<?php
declare(strict_types=1);
require_once dirname(__DIR__,2).'/includes/capacitaciones.php';
$items=capacitacionesPublicasWebsite();$cupos=[];
if($items){$ids=array_map(static fn($c)=>(int)$c['id'],$items);$marks=implode(',',array_fill(0,count($ids),'?'));$q=obtenerConexion()->prepare("SELECT asignatura_id,SUM(GREATEST(capacidad_maxima-cantidad_actual,0)) disponibles FROM capacitacion_secciones WHERE asignatura_id IN($marks) AND estado='abierta' GROUP BY asignatura_id");$q->execute($ids);$cupos=$q->fetchAll(PDO::FETCH_KEY_PAIR);}
$pageTitle='Capacitaciones | Atenea';$pageDescription='Explora las capacitaciones de Atenea en naturopatía y bienestar holístico.';$pageClass='courses-page';$activePage='capacitaciones';require dirname(__DIR__,2).'/includes/header.php';
?><main class="main"><div class="page-title" data-aos="fade"><div class="heading"><div class="container"><div class="row justify-content-center text-center"><div class="col-lg-8"><h1>Capacitaciones</h1><p class="mb-0">Programas creados para fortalecer tus conocimientos y llevar el bienestar holístico a la práctica.</p></div></div></div></div><nav class="breadcrumbs"><div class="container"><ol><li><a href="<?=atenea_url('index.php')?>">Inicio</a></li><li class="current">Capacitaciones</li></ol></div></nav></div><section class="courses section"><div class="container"><div class="row g-4"><?php foreach($items as$i=>$c):$url=atenea_url('src/website/capacitacion.php?slug='.rawurlencode($c['slug']));$anterior=(float)($c['precio_anterior']??0);$precio=(float)$c['precio'];$ahora=date('Y-m-d H:i:s');$promocion=$anterior>$precio&&empty($c['promocion_desde'])||$anterior>$precio&&$c['promocion_desde']<=$ahora&&(!$c['promocion_hasta']||$c['promocion_hasta']>=$ahora);?><div class="col-xl-4 col-md-6 d-flex" data-aos="zoom-in" data-aos-delay="<?=min(($i+1)*100,400)?>"><article class="course-item d-flex flex-column w-100"><a class="course-cover" href="<?=$url?>"><img src="<?=rutaImagenContenido($c['imagen'],'src/website/assets/img/course-1.jpg')?>" alt="<?=atenea_e($c['nombre'])?>" loading="lazy"></a><div class="course-content d-flex flex-column flex-grow-1"><div class="course-badges"><span><?=atenea_e(ucfirst($c['tipo']))?></span><?php if($c['nivel']):?><span><?=atenea_e($c['nivel'])?></span><?php endif;?><?php if($promocion&&$c['promocion_etiqueta']):?><span class="course-promo"><?=atenea_e($c['promocion_etiqueta'])?></span><?php endif;?></div><h2 class="course-title"><a href="<?=$url?>"><?=atenea_e($c['nombre'])?></a></h2><p class="description"><?=atenea_e($c['descripcion_corta'])?></p><dl class="course-meta"><div><dt><i class="bi bi-clock me-1"></i>Duración</dt><dd><?=atenea_e($c['duracion']?:'Por confirmar')?></dd></div><div><dt><i class="bi bi-display me-1"></i>Modalidad</dt><dd><?=atenea_e(ucfirst($c['modalidad']))?></dd></div><?php if(isset($cupos[$c['id']])):?><div><dt><i class="bi bi-people me-1"></i>Cupos disponibles</dt><dd><?=(int)$cupos[$c['id']]?></dd></div><?php endif;?></dl><div class="course-price-block"><span class="course-price-label">Inversión</span><?php if($promocion):?><del>$<?=number_format($anterior,2)?> USD</del><?php endif;?><strong>$<?=number_format($precio,2)?> <small>USD</small></strong></div><div class="course-actions mt-auto"><a class="btn course-details-button" href="<?=$url?>">Ver detalles</a><a class="course-action" href="<?=$url?>"><?=$precio>0?'Pagar':'Inscribirse'?></a></div></div></article></div><?php endforeach;?><?php if(!$items):?><div class="col-12 text-center py-5"><h2>No hay capacitaciones publicadas</h2></div><?php endif;?></div></div></section></main><?php require dirname(__DIR__,2).'/includes/footer.php';
